1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	const RUNE_BASE_PREMIUM = 25;
8	const THREE_ALIKE_BLOCK_PREMIUM = 60;
9	
10	const basePremiumForGroup = (count: number): number =>
11	  count === 3 ? THREE_ALIKE_BLOCK_PREMIUM : count * RUNE_BASE_PREMIUM;
12	
13	const basePremiumFor = (items: Item[]): number => {
14	  const countsByType = new Map<string, number>();
15	  for (const item of items) {
16	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
17	  }
18	  let total = 0;
19	  for (const count of countsByType.values()) total += basePremiumForGroup(count);
20	  return total;
21	};
22	
23	const applyFirstInsuranceSurcharge = (premium: number): number =>
24	  premium + (premium * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100;
25	
26	const quotePremium = (items: Item[]): number =>
27	  Math.ceil(applyFirstInsuranceSurcharge(basePremiumFor(items))) + PROCESSING_FEE;
28	
29	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
30	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
31	  return { results };
32	};
