const groupByType = (items: Item[]): Map<string, Item[]> =>
  items.reduce((groups, item) => {
    const group = groups.get(item.type) ?? [];
    return groups.set(item.type, [...group, item]);
  }, new Map<string, Item[]>());

const basePremiumForGroup = (group: Item[]): number =>
  group.length === 3 ? THREE_ALIKE_BLOCK_PREMIUM : group.length * RUNE_BASE_PREMIUM;

const basePremiumFor = (items: Item[]): number =>
  [...groupByType(items).values()]
    .reduce((sum, group) => sum + basePremiumForGroup(group), 0);
